import { Injectable, inject, DestroyRef, Type } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { MessageService } from 'primeng/api';
import { finalize, Observable, map, catchError } from 'rxjs';

import { DetailsComponentFactory } from '../../factories';
import {
  SimCardsDataAdapter,
  AssetsDataAdapter,
  AssetTagsDataAdapter,
  DeviceConfigProfilesDataAdapter,
  DevicesDataAdapter,
  GeofencesDataAdapter,
  AlertsDataAdapter,
  DeviceProvidersDataAdapter,
  SmsGatewayProvidersDataAdapter,
  IoTypesDataAdapter,
  OverspeedProfilesDataAdapter,
  UserRolesDataAdapter,
  UsersDataAdapter,
  CustomFieldsDataAdapter,
  ThemesDataAdapter,
  CostCentresDataAdapter,
  GeofenceGroupsDataAdapter,
  AssetGroupsDataAdapter,
  AssetCategoriesDataAdapter,
  ClientsDataAdapter,
  VendorsDataAdapter,
  AssetRatingProfilesDataAdapter,
  DistributorsDataAdapter,
} from '../adapters';
import { EntityDetailsStateService } from './entity-details.state.service';
import { isDefined, isEmpty } from '../../../../shared/utils';
import { BaseEntity } from '../../../../shared/models';
import { EmailProvidersDataAdapter } from '../adapters/email-providers-data-adapter.service';

@Injectable({ providedIn: 'root' })
export class EntityDetailsLoaderService {
  private readonly messageService = inject(MessageService);
  private readonly detailsFactory = inject(DetailsComponentFactory);
  private readonly stateService = inject(EntityDetailsStateService);
  private readonly simCardsDataAdapter = inject(SimCardsDataAdapter);
  private readonly devicesDataAdapter = inject(DevicesDataAdapter);
  private readonly geofencesDataAdapter = inject(GeofencesDataAdapter);
  private readonly deviceProvidersDataAdapter = inject(
    DeviceProvidersDataAdapter,
  );
  private readonly smsGatewayProvidersDataAdapter = inject(
    SmsGatewayProvidersDataAdapter,
  );
  private readonly ioTypesDataAdapter = inject(IoTypesDataAdapter);

  private readonly alertsDataAdapter = inject(AlertsDataAdapter);
  private readonly destroyRef = inject(DestroyRef);
  private readonly assetsDataAdapter = inject(AssetsDataAdapter);
  private readonly assetTagsDataAdapter = inject(AssetTagsDataAdapter);
  private readonly deviceConfigProfilesDataAdapter = inject(
    DeviceConfigProfilesDataAdapter,
  );
  private readonly overspeedProfilesDataAdapter = inject(
    OverspeedProfilesDataAdapter,
  );
  private readonly userRolesDataAdapter = inject(UserRolesDataAdapter);
  private readonly userDataAdapter = inject(UsersDataAdapter);
  private readonly customFieldsDataAdapter = inject(CustomFieldsDataAdapter);
  private readonly themeDataAdapter = inject(ThemesDataAdapter);
  private readonly costCentresDataAdapter = inject(CostCentresDataAdapter);
  private readonly geofenceGroupsDataAdapter = inject(
    GeofenceGroupsDataAdapter,
  );
  private readonly assetGroupsDataAdapter = inject(AssetGroupsDataAdapter);
  private readonly assetCategoriesDataAdapter = inject(
    AssetCategoriesDataAdapter,
  );
  private readonly emailProvidersDataAdapter = inject(
    EmailProvidersDataAdapter,
  );
  private readonly clientsDataAdapter = inject(ClientsDataAdapter);
  private readonly vendorsDataAdapter = inject(VendorsDataAdapter);
  private readonly assetRatingProfilesDataAdapter = inject(
    AssetRatingProfilesDataAdapter,
  );
  private readonly distributorsDataAdapter = inject(DistributorsDataAdapter);

  /**
   * Loads entity details from ID and type
   */
  loadEntityDetails(entityType: string, entityId: string): void {
    const component = this.detailsFactory.getDetailsComponent(entityType);

    this.loadEntityWithCallbacks(
      entityType,
      entityId,
      (item) => this.handleLoadSuccess(item, entityType, component),
      () => this.handleLoadError(entityType),
      `Failed to load ${entityType} details`,
    );
  }

  /**
   * Soft loads entity details for refresh without affecting UI state like accordion expansion
   */
  softLoadEntityDetails(entityType: string, entityId: string): void {
    this.loadEntityWithCallbacks(
      entityType,
      entityId,
      (item) => this.handleSoftLoadSuccess(item, entityType),
      () => this.handleSoftLoadError(entityType),
      `Failed to refresh ${entityType} details`,
    );
  }

  /**
   * Soft loads entity details and returns an Observable for better async handling
   * This allows the state service to properly manage its own loading state
   */
  softLoadEntityDetailsObservable(
    entityType: string,
    entityId: string,
  ): Observable<BaseEntity | null> {
    try {
      // Get the appropriate service
      const entityService = this.getServiceForEntityType(entityType);

      if (isEmpty(entityService)) {
        this.messageService.add({
          severity: 'error',
          summary: 'Error',
          detail: `No service available for entity type: ${entityType}`,
        });
        return new Observable<BaseEntity | null>((subscriber) => {
          subscriber.next(null);
          subscriber.complete();
        });
      }

      // Return the observable with proper error handling
      return entityService.getById(entityId).pipe(
        takeUntilDestroyed(this.destroyRef),
        map((item: unknown) => {
          const baseEntity = item as BaseEntity;
          if (isDefined(baseEntity)) {
            // Add entityType if not present
            return { ...baseEntity, entityType: entityType };
          }
          return null;
        }),
        catchError((error) => {
          this.messageService.add({
            severity: 'error',
            summary: 'Error',
            detail: `Failed to refresh ${entityType} details`,
          });
          console.error('Soft load error:', error);
          return new Observable<BaseEntity | null>((subscriber) => {
            subscriber.next(null);
            subscriber.complete();
          });
        }),
      );
    } catch (error) {
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Failed to refresh ${entityType} details: ${error}`,
      });
      return new Observable<BaseEntity | null>((subscriber) => {
        subscriber.next(null);
        subscriber.complete();
      });
    }
  }

  /**
   * Common helper method for loading entity details with custom callbacks
   */
  private loadEntityWithCallbacks(
    entityType: string,
    entityId: string,
    onSuccess: (item: BaseEntity) => void,
    onError: () => void,
    errorMessage: string,
  ): void {
    this.stateService.isLoading.set(true);

    try {
      // Get the appropriate service
      const entityService = this.getServiceForEntityType(entityType);

      if (isEmpty(entityService)) {
        this.handleMissingService();
        return;
      }

      // Load entity data
      entityService
        .getById(entityId)
        .pipe(
          takeUntilDestroyed(this.destroyRef),
          finalize(() => this.stateService.isLoading.set(false)),
        )
        .subscribe({
          next: (item) => onSuccess(item),
          error: () => onError(),
        });
    } catch (error) {
      this.stateService.isLoading.set(false);
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `${errorMessage}: ${error}`,
      });

      // Only close panel for hard loads, not soft loads
      if (errorMessage.includes('Failed to load')) {
        this.stateService.closeDetailsPanel();
      }
    }
  }

  /**
   * Handle case when no service is available
   */
  private handleMissingService(): void {
    this.stateService.isLoading.set(false);
  }

  /**
   * Handle successful entity load
   */
  private handleLoadSuccess(
    item: BaseEntity,
    entityType: string,
    component: Type<unknown>,
  ): void {
    if (isDefined(item)) {
      // Add entityType if not present
      const itemWithType = { ...item, entityType: entityType };
      this.stateService.openDetailsPanel(itemWithType, component);
    } else {
      this.messageService.add({
        severity: 'error',
        summary: 'Not Found',
        detail: `${entityType} not found`,
      });
      this.stateService.closeDetailsPanel();
    }
  }

  /**
   * Handle successful soft entity load (preserves UI state)
   */
  private handleSoftLoadSuccess(item: BaseEntity, entityType: string): void {
    if (isDefined(item)) {
      // Add entityType if not present and update using soft method
      const itemWithType = { ...item, entityType: entityType };
      this.stateService.softRefreshSelectedItem(itemWithType);
    } else {
      this.messageService.add({
        severity: 'error',
        summary: 'Not Found',
        detail: `${entityType} not found`,
      });
      // Don't close the panel, just clear loading state
    }
  }

  /**
   * Handle entity load error
   */
  private handleLoadError(entityType: string): void {
    this.messageService.add({
      severity: 'error',
      summary: 'Error',
      detail: `Failed to load ${entityType} details`,
    });
    this.stateService.closeDetailsPanel();
  }

  /**
   * Handle soft entity load error (preserves UI state)
   */
  private handleSoftLoadError(entityType: string): void {
    this.messageService.add({
      severity: 'error',
      summary: 'Error',
      detail: `Failed to refresh ${entityType} details`,
    });
    // Don't close the panel, keep existing data visible
  }

  /**
   * Get the appropriate service for the entity type
   */
  private getServiceForEntityType(entityType: string): {
    getById(id: string): Observable<BaseEntity>;
  } {
    // Return the appropriate service based on entity type
    switch (entityType.toLowerCase()) {
      case 'client-sim-cards':
      case 'simcard':
        return this.simCardsDataAdapter;
      case 'client-assets':
      case 'asset':
        return this.assetsDataAdapter;
      case 'client-asset-tags':
      case 'asset-tag':
        return this.assetTagsDataAdapter;
      case 'client-device-config-profiles':
      case 'vendor-device-config-profiles':
      case 'device-config-profile':
        return this.deviceConfigProfilesDataAdapter;
      case 'client-hardware-devices':
      case 'device':
        return this.devicesDataAdapter;
      case 'client-geofences':
      case 'geofence':
        return this.geofencesDataAdapter;
      case 'client-alerts':
      case 'alert':
        return this.alertsDataAdapter;
      case 'client-device-providers':
      case 'distributor-device-providers':
      case 'device-provider':
        return this.deviceProvidersDataAdapter;
      case 'client-sms-gateway-providers':
      case 'sms-gateway-provider':
      case 'vendor-sms-gateway-providers':
        return this.smsGatewayProvidersDataAdapter;
      case 'email-provider':
      case 'vendor-email-provider':
        return this.emailProvidersDataAdapter;
      case 'client-io-types':
      case 'vendor-io-types':
      case 'io-type':
        return this.ioTypesDataAdapter;
      case 'client-overspeed-profiles':
      case 'vendor-overspeed-profiles':
      case 'distributor-overspeed-profiles':
      case 'overspeed-profile':
        return this.overspeedProfilesDataAdapter;
      case 'client-user-roles':
      case 'vendor-user-roles':
      case 'distributor-user-roles':
      case 'user-role':
        return this.userRolesDataAdapter;
      case 'client-users':
      case 'vendor-users':
      case 'distributor-users':
      case 'user':
        return this.userDataAdapter;
      case 'client-custom-fields':
      case 'vendor-custom-fields':
      case 'custom-field':
        return this.customFieldsDataAdapter;
      case 'distributor-themes':
      case 'theme':
        return this.themeDataAdapter;
      case 'client-cost-centres':
      case 'cost-centre':
        return this.costCentresDataAdapter;
      case 'client-geofence-groups':
      case 'geofence-group':
        return this.geofenceGroupsDataAdapter;
      case 'client-asset-groups':
      case 'asset-group':
        return this.assetGroupsDataAdapter;
      case 'client-asset-categories':
      case 'asset-category':
        return this.assetCategoriesDataAdapter;
      case 'vendor-clients':
      case 'client':
        return this.clientsDataAdapter;
      case 'distributor-vendors':
      case 'vendor':
        return this.vendorsDataAdapter;
      case 'client-asset-rating-profiles':
      case 'asset-rating-profile':
        return this.assetRatingProfilesDataAdapter;
      case 'super-admin-distributors':
      case 'distributor':
        return this.distributorsDataAdapter;
      default:
        // Handle unknown entity type
        this.messageService.add({
          severity: 'error',
          summary: 'Error',
          detail: `Unknown entity type: ${entityType}`,
        });
        this.stateService.closeDetailsPanel();
        return { getById: () => new Observable<BaseEntity>() };
    }
  }
}
